<template>
  <GuideLayout>
    <!-- 页面标题 -->
    <div class="ch-header">
      <span class="ch-header__num">第 3 章</span>
      <h1 class="ch-header__title">FlowDesigner 参数与方法</h1>
      <p class="ch-header__desc">
        FlowDesigner 是流程设计器的核心类，封装了画布管理、状态管理、权限控制等核心功能。
        本章节详细介绍 FlowDesigner 类的公共属性、方法和回调函数。
      </p>
    </div>

    <!-- 导航目录 -->
    <nav class="ch-toc">
      <h3 class="ch-toc__title">目录</h3>
      <ul class="ch-toc__list">
        <li><a href="#constructor" @click.prevent="scrollToSection('constructor')">构造函数</a></li>
        <li><a href="#properties" @click.prevent="scrollToSection('properties')">公共属性</a></li>
        <li><a href="#graph-api" @click.prevent="scrollToSection('graph-api')">Graph 相关</a></li>
        <li><a href="#state-api" @click.prevent="scrollToSection('state-api')">状态管理</a></li>
        <li><a href="#mode-api" @click.prevent="scrollToSection('mode-api')">模式与权限</a></li>
        <li><a href="#config-api" @click.prevent="scrollToSection('config-api')">配置管理</a></li>
        <li><a href="#history-api" @click.prevent="scrollToSection('history-api')">历史记录</a></li>
        <li><a href="#data-api" @click.prevent="scrollToSection('data-api')">数据操作</a></li>
        <li><a href="#view-api" @click.prevent="scrollToSection('view-api')">视图操作</a></li>
        <li><a href="#group-api" @click.prevent="scrollToSection('group-api')">成组功能</a></li>
        <li><a href="#edge-state-api" @click.prevent="scrollToSection('edge-state-api')">边状态管理</a></li>
        <li><a href="#node-state-api" @click.prevent="scrollToSection('node-state-api')">节点状态管理</a></li>
        <li><a href="#callbacks" @click.prevent="scrollToSection('callbacks')">回调注册</a></li>
        <li><a href="#other-api" @click.prevent="scrollToSection('other-api')">其他方法</a></li>
      </ul>
    </nav>

    <!-- 构造函数 -->
    <section id="constructor" class="ch-section">
      <h2 class="ch-section__title">构造函数</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>new FlowDesigner(options: FlowDesignerOptions)</code>
        </h3>
        <p class="api-item__desc">创建 FlowDesigner 实例。</p>

        <h4>参数说明</h4>
        <table class="api-table">
          <thead>
            <tr>
              <th>参数</th>
              <th>类型</th>
              <th>必填</th>
              <th>说明</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td><code>container</code></td>
              <td><code>HTMLElement</code></td>
              <td>是</td>
              <td>画布容器 DOM 元素</td>
            </tr>
            <tr>
              <td><code>id</code></td>
              <td><code>string</code></td>
              <td>否</td>
              <td>画布唯一标识（默认自动生成）</td>
            </tr>
            <tr>
              <td><code>minimapContainer</code></td>
              <td><code>HTMLElement</code></td>
              <td>否</td>
              <td>小地图容器 DOM 元素</td>
            </tr>
            <tr>
              <td><code>tooltipContainer</code></td>
              <td><code>HTMLElement</code></td>
              <td>否</td>
              <td>Tooltip 容器元素（由 FlowDesignerLayout 内部传入）</td>
            </tr>
            <tr>
              <td><code>initialMeta</code></td>
              <td><code>Partial&lt;FlowMeta&gt;</code></td>
              <td>否</td>
              <td>初始流程元数据</td>
            </tr>
            <tr>
              <td><code>initialConfig</code></td>
              <td><code>Partial&lt;CanvasConfig&gt;</code></td>
              <td>否</td>
              <td>初始画布配置</td>
            </tr>
            <tr>
              <td><code>mode</code></td>
              <td><code>string</code></td>
              <td>否</td>
              <td>初始模式（默认 'design'，支持自定义模式名）</td>
            </tr>
            <tr>
              <td><code>permissionConfig</code></td>
              <td><code>Record&lt;string, Partial&lt;ModeCapabilities&gt;&gt;</code></td>
              <td>否</td>
              <td>权限配置映射表（定义多个模式的权限）</td>
            </tr>
            <tr>
              <td><code>permissions</code></td>
              <td><code>Partial&lt;ModeCapabilities&gt;</code></td>
              <td>否</td>
              <td>直接覆盖当前模式的权限（优先级最高）</td>
            </tr>
            <tr>
              <td><code>getPermissions</code></td>
              <td><code>(mode: string) => ModeCapabilities</code></td>
              <td>否</td>
              <td>自定义权限解析函数（完全接管权限计算）</td>
            </tr>
            <tr>
              <td><code>shortcuts</code></td>
              <td><code>ShortcutMap</code></td>
              <td>否</td>
              <td>自定义快捷键映射表</td>
            </tr>
            <tr>
              <td><code>callbacks</code></td>
              <td><code>Partial&lt;FlowDesignerCallbacks&gt;</code></td>
              <td>否</td>
              <td>事件回调（支持生命周期拦截器）</td>
            </tr>
          </tbody>
        </table>
      </div>
    </section>

    <!-- 公共属性 -->
    <section id="properties" class="ch-section">
      <h2 class="ch-section__title">公共属性</h2>

      <div class="api-item">
        <h3 class="api-item__signature"><code>readonly id: string</code></h3>
        <p class="api-item__desc">画布唯一标识（只读）。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>readonly selectedCells: Ref&lt;SelectedCell[]&gt;</code></h3>
        <p class="api-item__desc">当前选中的单元格列表（响应式，可用于 Vue provide/inject）。</p>
        <div class="api-item__example">
          <pre><code>// 在 Vue 组件中使用
const selectedCells = designer.selectedCells
watch(selectedCells, (cells) => {
  console.log('选中变化:', cells)
})</code></pre>
        </div>
      </div>
    </section>

    <!-- Graph 相关 -->
    <section id="graph-api" class="ch-section">
      <h2 class="ch-section__title">Graph 相关</h2>

      <div class="api-item">
        <h3 class="api-item__signature"><code>getGraph(): Graph</code></h3>
        <p class="api-item__desc">获取 X6 Graph 实例，可直接调用 X6 的原生 API。</p>
        <div class="api-item__example">
          <pre><code>const graph = designer.getGraph()
// 调用 X6 原生 API
graph.zoom(0.1)
graph.centerContent()</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>getRootNodes(): Node[]</code></h3>
        <p class="api-item__desc">获取画布中的顶层起始节点（入度为 0 的节点）。</p>
        <div class="api-item__example">
          <pre><code>const rootNodes = designer.getRootNodes()
console.log('起始节点:', rootNodes)</code></pre>
        </div>
      </div>
    </section>

    <!-- 状态管理 -->
    <section id="state-api" class="ch-section">
      <h2 class="ch-section__title">状态管理</h2>

<!--      <div class="api-item">-->
<!--        <h3 class="api-item__signature"><code>getMeta(): FlowMeta</code></h3>-->
<!--        <p class="api-item__desc">获取流程元数据。</p>-->
<!--      </div>-->
<!--      -->
<!--      <div class="api-item">-->
<!--        <h3 class="api-item__signature"><code>setMeta(meta: Partial&lt;FlowMeta&gt;): void</code></h3>-->
<!--        <p class="api-item__desc">设置流程元数据（部分更新）。</p>-->
<!--        <div class="api-item__example">-->
<!--          <pre><code>designer.setMeta({-->
<!--  name: '我的流程',-->
<!--  version: '1.0.0',-->
<!--  description: '流程描述'-->
<!--})</code></pre>-->
<!--        </div>-->
<!--      </div>-->

      <div class="api-item">
        <h3 class="api-item__signature"><code>reset(meta?: Partial&lt;FlowMeta&gt;): void</code></h3>
        <p class="api-item__desc">重置流程状态（清空选中、重置元数据）。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>isDirty(): boolean</code></h3>
        <p class="api-item__desc">判断流程是否有未保存的修改。</p>
      </div>
    </section>

    <!-- 模式与权限 -->
    <section id="mode-api" class="ch-section">
      <h2 class="ch-section__title">模式与权限</h2>

      <div class="api-item">
        <h3 class="api-item__signature"><code>getMode(): DesignerMode</code></h3>
        <p class="api-item__desc">获取当前模式。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>setMode(mode: DesignerMode): void</code></h3>
        <p class="api-item__desc">切换设计器模式。</p>
        <div class="api-item__example">
          <pre><code>designer.setMode('readonly') // 切换到只读模式
designer.setMode('design')   // 切换到设计模式</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>getCapabilities(): ModeCapabilities</code></h3>
        <p class="api-item__desc">获取当前模式的完整权限配置。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>can(capability: keyof ModeCapabilities): boolean</code></h3>
        <p class="api-item__desc">检查当前模式是否拥有某项权限。</p>
        <div class="api-item__example">
          <pre><code>if (designer.can('canDrag')) {
  console.log('允许拖拽节点')
}
if (designer.can('canDelete')) {
  console.log('允许删除节点')
}</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>updatePermissions(options: { permissionConfig?, permissions?, getPermissions? }): void</code>
        </h3>
        <p class="api-item__desc">动态更新权限配置并立即同步到 X6 Graph。支持三种更新方式。</p>
        <div class="api-item__example">
          <pre><code>// 方式1：直接覆盖权限
designer.updatePermissions({
  permissions: { canDrag: false, canDelete: false }
})

// 方式2：更新模式配置映射表
designer.updatePermissions({
  permissionConfig: {
    review: { canEdit: false, canExport: true }
  }
})

// 方式3：使用自定义函数
designer.updatePermissions({
  getPermissions: (mode) => calculatePermissionsByUserRole(mode)
})</code></pre>
        </div>
      </div>
    </section>

    <!-- 配置管理 -->
    <section id="config-api" class="ch-section">
      <h2 class="ch-section__title">配置管理</h2>

      <div class="api-item">
        <h3 class="api-item__signature"><code>getCanvasConfig(): CanvasConfig</code></h3>
        <p class="api-item__desc">获取当前画布配置。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>updateCanvasConfig(update: Partial&lt;CanvasConfig&gt;): void</code></h3>
        <p class="api-item__desc">更新画布配置（深度合并）。</p>
        <div class="api-item__example">
          <pre><code>designer.updateCanvasConfig({
  grid: { size: 20, visible: true },
  background: { color: '#f5f5f5' }
})</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>applyConfig(): void</code></h3>
        <p class="api-item__desc">应用配置到 Graph（需在 updateCanvasConfig 后调用以生效）。</p>
        <div class="api-item__example">
          <pre><code>designer.updateCanvasConfig({ grid: { size: 20 } })
designer.applyConfig() // 使配置生效</code></pre>
        </div>
      </div>
    </section>

    <!-- 历史记录 -->
    <section id="history-api" class="ch-section">
      <h2 class="ch-section__title">历史记录</h2>

      <div class="api-item">
        <h3 class="api-item__signature"><code>undo(): boolean</code></h3>
        <p class="api-item__desc">撤销操作。返回是否成功撤销。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>redo(): boolean</code></h3>
        <p class="api-item__desc">重做操作。返回是否成功重做。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>canUndo(): boolean</code></h3>
        <p class="api-item__desc">判断是否可以撤销。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>canRedo(): boolean</code></h3>
        <p class="api-item__desc">判断是否可以重做。</p>
      </div>
    </section>

    <!-- 数据操作 -->
    <section id="data-api" class="ch-section">
      <h2 class="ch-section__title">数据操作</h2>

<!--      <div class="api-item">-->
<!--        <h3 class="api-item__signature"><code>save(): void</code></h3>-->
<!--        <p class="api-item__desc">保存流程数据（触发 onSave 回调）。</p>-->
<!--        <div class="api-item__example">-->
<!--          <pre><code>designer.onSave((data) => {-->
<!--  console.log('保存数据:', data)-->
<!--  // 发送到后端-->
<!--  api.saveFlow(data)-->
<!--})-->

<!--// 触发保存-->
<!--designer.save()</code></pre>-->
<!--        </div>-->
<!--      </div>-->

      <div class="api-item">
        <h3 class="api-item__signature"><code>load(data: FlowData): void</code></h3>
        <p class="api-item__desc">加载流程数据到画布。</p>
        <div class="api-item__example">
          <pre><code>const flowData = await api.getFlow(id)
designer.load(flowData)</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>export(format: 'json' | 'png' | 'svg'): any</code></h3>
        <p class="api-item__desc">导出流程数据或图片。</p>
        <div class="api-item__example">
          <pre><code>// 导出 JSON
const jsonData = designer.export('json')

// 导出 PNG 图片
const pngDataURL = designer.export('png')

// 导出 SVG
const svgString = designer.export('svg')</code></pre>
        </div>
      </div>
    </section>

    <!-- 视图操作 -->
    <section id="view-api" class="ch-section">
      <h2 class="ch-section__title">视图操作</h2>

      <div class="api-item">
        <h3 class="api-item__signature"><code>zoom(factor: number): void</code></h3>
        <p class="api-item__desc">缩放画布（增量）。</p>
        <div class="api-item__example">
          <pre><code>designer.zoom(0.1)  // 放大 10%
designer.zoom(-0.1) // 缩小 10%</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>zoomTo(scale: number): void</code></h3>
        <p class="api-item__desc">缩放到指定比例（绝对值）。</p>
        <div class="api-item__example">
          <pre><code>designer.zoomTo(1.5) // 缩放到 150%
designer.zoomTo(1)   // 恢复到 100%</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>fitToContent(padding?: number): void</code></h3>
        <p class="api-item__desc">自适应画布内容（适应视口）。</p>
        <div class="api-item__example">
          <pre><code>designer.fitToContent(40) // 带 40px 内边距</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>centerContent(): void</code></h3>
        <p class="api-item__desc">居中显示画布内容。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>resetView(): void</code></h3>
        <p class="api-item__desc">重置视图（缩放到 100% 并居中）。需要 canResetView 权限。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>toggleMinimap(): boolean</code></h3>
        <p class="api-item__desc">切换小地图折叠状态。返回切换后的新状态（true = 折叠）。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>isMinimapCollapsed(): boolean</code></h3>
        <p class="api-item__desc">获取小地图当前折叠状态。</p>
      </div>
    </section>

    <!-- 成组功能 -->
    <section id="group-api" class="ch-section">
      <h2 class="ch-section__title">成组功能</h2>

      <div class="api-item">
        <h3 class="api-item__signature"><code>groupSelectedNodes(): boolean</code></h3>
        <p class="api-item__desc">将选中的节点成组。返回是否成功。</p>
        <div class="api-item__example">
          <pre><code>if (designer.canGroup()) {
  designer.groupSelectedNodes()
}</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>ungroupSelected(): boolean</code></h3>
        <p class="api-item__desc">解组选中的组节点。返回是否成功。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>canGroup(): boolean</code></h3>
        <p class="api-item__desc">检查当前选中的节点是否可以成组。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>canUngroup(): boolean</code></h3>
        <p class="api-item__desc">检查当前选中的节点是否可以解组。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>toggleGroupCollapse(group: Node): boolean</code></h3>
        <p class="api-item__desc">切换分组节点的展开/收起状态。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>expandGroup(group: Node): boolean</code></h3>
        <p class="api-item__desc">展开分组节点。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>collapseGroup(group: Node): boolean</code></h3>
        <p class="api-item__desc">收起分组节点。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>fitGroupSize(group: Node): void</code></h3>
        <p class="api-item__desc">自动调整分组节点尺寸以适应子节点。</p>
      </div>
    </section>

    <!-- 边状态管理 -->
    <section id="edge-state-api" class="ch-section">
      <h2 class="ch-section__title">边状态管理</h2>

      <div class="api-item">
        <h3 class="api-item__signature"><code>setEdgeLabel(edge: Edge, label?: string, state?: 'default' | 'selected' | 'hover' | 'flowing'): void</code></h3>
        <p class="api-item__desc">设置连线标签文本和状态。</p>
        <div class="api-item__example">
          <pre><code>const edge = graph.getEdges()[0]
designer.setEdgeLabel(edge, '条件A', 'selected')</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>registerEdgeStateHandler(stateName: string, handler: EdgeStateHandler, override?: boolean): void</code>
        </h3>
        <p class="api-item__desc">注册或覆盖边状态处理器（用于自定义状态样式）。</p>
        <div class="api-item__example">
          <pre><code>designer.registerEdgeStateHandler('warning', {
  apply: (edge, config) => {
    edge.attr('line/stroke', '#ff4d4f')
    edge.attr('line/strokeWidth', 3)
  },
  cleanup: (edge, config) => {
    edge.attr('line/stroke', config.connection.strokeColor)
    edge.attr('line/strokeWidth', config.connection.strokeWidth)
  }
})</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>getEdgeStateHandler(stateName: string): EdgeStateHandler | undefined</code></h3>
        <p class="api-item__desc">获取已注册的边状态处理器。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>unregisterEdgeStateHandler(stateName: string): boolean</code></h3>
        <p class="api-item__desc">移除边状态处理器。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>getRegisteredEdgeStates(): string[]</code></h3>
        <p class="api-item__desc">获取所有已注册的边状态名称。</p>
      </div>
    </section>

    <!-- 节点状态管理 -->
    <section id="node-state-api" class="ch-section">
      <h2 class="ch-section__title">节点状态管理</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>registerNodeStateHandler(stateName: string, handler: NodeStateHandler, override?: boolean): void</code>
        </h3>
        <p class="api-item__desc">注册或覆盖节点状态处理器（用于自定义状态样式）。</p>
        <div class="api-item__example">
          <pre><code>designer.registerNodeStateHandler('error', {
  apply: (node) => {
    node.attr('body/stroke', '#ff4d4f')
    node.attr('body/strokeWidth', 3)
  },
  cleanup: (node) => {
    node.attr('body/stroke', '#d9d9d9')
    node.attr('body/strokeWidth', 1)
  }
})</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>getNodeStateHandler(stateName: string): NodeStateHandler | undefined</code></h3>
        <p class="api-item__desc">获取已注册的节点状态处理器。</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature"><code>unregisterNodeStateHandler(stateName: string): boolean</code></h3>
        <p class="api-item__desc">移除节点状态处理器。</p>
      </div>

      <div class="api-item">
