<script setup lang="ts">
import GuideLayout from '../components/GuideLayout.vue'

/**
 * 滚动到指定 section
 * 因为 GuideLayout 使用了独立的滚动容器 (.guide-content)，
 * 需要手动查找父级滚动容器并滚动到目标元素
 */
function scrollToSection(sectionId: string) {
  const targetElement = document.getElementById(sectionId)
  if (!targetElement) return

  // 查找最近的可滚动父容器（GuideLayout 的 .guide-content）
  const scrollContainer = targetElement.closest('.guide-content') as HTMLElement
  if (!scrollContainer) {
    // 兜底：如果找不到，使用全局滚动
    targetElement.scrollIntoView({ behavior: 'smooth', block: 'start' })
    return
  }

  // 计算目标元素相对于滚动容器的位置
  const containerRect = scrollContainer.getBoundingClientRect()
  const targetRect = targetElement.getBoundingClientRect()
  const offsetTop = targetRect.top - containerRect.top + scrollContainer.scrollTop - 20 // 减去 20px 留白

  // 平滑滚动
  scrollContainer.scrollTo({
    top: offsetTop,
    behavior: 'smooth'
  })
}
</script>

